# --- Action Group Tools ---
action_group_tools = []

@tool
def get_owner_info(ownerId: str) -> str:
    """Retrieve the profile of a private jet owner — name and home airport — by owner ID."""
    if ownerId in OWNERS:
        return json.dumps(OWNERS[ownerId])
    return json.dumps({"error": f"Owner '{ownerId}' not found."})

action_group_tools.append(get_owner_info)

@tool
def get_passengers(ownerId: str) -> str:
    """List the family members and registered passengers associated with an owner."""
    if ownerId in PASSENGERS:
        return json.dumps({"ownerId": ownerId, "passengers": PASSENGERS[ownerId]})
    return json.dumps({"error": f"No passengers found for owner '{ownerId}'."})

action_group_tools.append(get_passengers)

@tool
def book_reservation(date: str, passengers: str, departureAirport: str, ownerId: str, arrivalAirport: str) -> str:
    """Book a private jet reservation for the owner and their registered passengers."""
    owner = OWNERS.get(ownerId, {"firstname": "Unknown", "lastname": "Owner"})
    try:
        pax = json.loads(passengers) if isinstance(passengers, str) else passengers
    except (json.JSONDecodeError, TypeError):
        pax = []

    return json.dumps({
        "confirmationId": f"PVT-{uuid.uuid4().hex[:8].upper()}",
        "ownerId": ownerId,
        "primaryPassenger": f"{owner['firstname']} {owner['lastname']}",
        "date": date,
        "departure": departureAirport,
        "arrival": arrivalAirport,
        "passengers": pax,
        "totalPassengers": len(pax) + 1,
        "status": "CONFIRMED",
        "bookedAt": datetime.utcnow().isoformat() + "Z",
    })

action_group_tools.append(book_reservation)


