def make_msg(role, text):
    return {
        "role": role,
        "content": [{"text": text}]
    }

def inference(model, messages, system_prompt=""):
    async def run_inference():
        results = []
        async for event in model.stream(messages=messages, system_prompt=system_prompt):
            results.append(event)
        return results

    response = asyncio.run(run_inference())

    text = ""
    for chunk in response:
        if "contentBlockDelta" not in chunk:
            continue
        text += chunk["contentBlockDelta"].get("delta", {}).get("text", "")

    return text

_agent = None
first_turn = True
last_input = ""
user_id = ""

# agent update loop
def get_agent():
    global _agent
    if _agent is None:
        system_prompt = ORCHESTRATION_TEMPLATE
        _agent = Agent(
            model=llm_ORCHESTRATION,
            system_prompt=system_prompt,
            tools=tools,
            conversation_manager=SlidingWindowConversationManager()
        )
    return _agent

def invoke_agent(question: str):
    global last_input
    last_input = question
    agent = get_agent()

    original_stdout = sys.stdout
    sys.stdout = io.StringIO()
    response = agent(question)
    sys.stdout = original_stdout
    return response


@app.entrypoint
async def invoke(payload, context):
    try:
        session_id = context.session_id or payload.get("sessionId", uuid.uuid4().hex[:8])

        tools_used.clear()
        agent_query = payload.get("prompt", "")
        if not agent_query:
            yield "No query provided, please provide a 'prompt' field in the payload."
            return

        agent_result = invoke_agent(agent_query)

        tools_used.update(list(agent_result.metrics.tool_metrics.keys()))
        response_content = str(agent_result)

        yield response_content if response_content else "No response."
    except Exception as e:
        yield f"Error: {e}"


